INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ヒヨリ", 155, "A", 16, 100101, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 0, "獣人族", "東山奈央", "トゥインクルウィッシュ", "人助け、応援", 27, "人助けが大好き！　前向き格闘娘", 44, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ユイ", 158, "O", 17, 100201, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 0, "ヒューマン", "種田梨沙", "トゥインクルウィッシュ", "料理、人間観察", 5, "戦闘のサポートが得意な、心優しい少女", 47, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("レイ", 163, "B", 18, 100301, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 0, "魔族", "早見沙織", "トゥインクルウィッシュ", "読書、乗馬、お茶", 12, "クールで何事にも真っ直ぐな剣士", 46, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミソギ", 128, "O", 9, 100401, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 8, 0, "ヒューマン", "諸星すみれ", "リトルリリカル", "いたずら、探検", 10, "探検好きのイタズラっ子", 27, 5);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("マツリ", 146, "O", 12, 100501, "？？？", 11, 0, "獣人族", "下田麻美", "王宮騎士団（NIGHTMARE）", "ヒーローごっこ", 25, "ヒーローに憧れる騎士見習いの少女", 40, 8);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アカリ", 150, "O", 13, 100601, "アカリ、まだわからないことが多くて…\nだからこれから\nいろいろ教えてくださいね、お兄ちゃん！", 11, 0, "魔族", "浅倉杏美", "悪魔偽王国軍（ディアボロス）", "サックス", 22, "甘え上手なみんなの人気者", 42, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミヤコ", 130, "B", 14, 100701, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 1, 0, "魔族", "雨宮天", "悪魔偽王国軍（ディアボロス）", "プリンを食べること", 23, "プリン大好きゴースト娘", 32, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ユキ", 150, "AB", 14, 100801, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 10, 0, "エルフ", "大空直美", "ヴァイスフリューゲル　ランドソル支部", "鏡で自分を見ること", 10, "ボクは誰よりも美しい", 40, 15);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アンナ", 159, "A", 17, 100901, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 0, "魔族", "髙野麻美", "トワイライトキャラバン", "小説執筆", 5, "前世を信じる中二病患者、「疾風の冥姫」", 45, 13);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("マホ", 155, "O", 16, 101001, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 0, "獣人族", "内田真礼", "自警団（カォン）", "空想、ぬいぐるみ集め", 22, "マホマホ王国のプリンセス", 42, 10);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("リノ", 156, "A", 15, 101101, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 0, "ヒューマン", "阿澄佳奈", "ラビリンス", "お裁縫", 25, "人懐っこくてマシンガントークな妹系少女", 44, 3);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ハツネ", 156, "A", 17, 101201, "私はハツネ！　困っている人の味方だよ！\n困った時は、いつでも言ってね♪\n私のちょ…ま、魔法で助けてあげるから！", 12, 0, "エルフ", "大橋彩香", "フォレスティエ", "妹と遊ぶこと、二度寝、昼寝、早寝", 24, "みんなのために超能力を使う眠り姫", 46, 6);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ナナカ", 166, "O", 18, 101301, "", 8, 0, "魔族", "佳村はるか", "トワイライトキャラバン", "読書、魔法", 21, "オタク全開な魔法少女", 55, 13);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("カスミ", 152, "AB", 15, 101401, "test", 11, 0, "獣人族", "水瀬いのり", "自警団（カォン）", "読書、推理", 3, "頭脳明晰な美少女名探偵", 41, 10);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミサト", 165, "O", 21, 101501, "test", 9, 0, "エルフ", "國府田マリ子", "フォレスティエ", "絵本作り", 5, "母性溢れる優しいみんなの「ミサト先生」", 54, 6);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("スズナ", 167, "O", 17, 101601, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 4, 0, "魔族", "上坂すみれ", "ルーセント学院", "ファッション", 10, "天真爛漫で人気者のカリスマモデル", 48, 14);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("カオリ", 158, "A", 17, 101701, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 7, 0, "獣人族", "高森奈津美", "自警団（カォン）", "踊り、空手", 7, "いつでも「なんくるないさ～」な天然娘", 53, 10);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("イオ", 162, "B", 23, 101801, "いつも助けてくれてありがとう\n私のほうが年上なのに\n頼ってばかりでごめんなさい～", 8, 0, "魔族", "伊藤静", "ルーセント学院", "恋愛小説、恋愛舞台、恋愛漫画の鑑賞", 14, "多くの男性を魅了する無垢な女教師", 52, 14);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミミ", 117, "O", 10, 102001, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 4, 0, "獣人族", "日高里菜", "リトルリリカル", "かわいいもの集め", 3, "お歌もにんじんも、ウサギさんも大好き♪", 21, 5);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("クルミ", 150, "B", 12, 102101, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 6, 0, "ヒューマン", "植田佳奈", "サレンディア救護院", "観劇、おままごと", 9, "泣き虫で臆病な守ってあげたい女の子", 40, 9);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ヨリ", 150, "O", 13, 102201, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 11, 0, "魔族", "原紗友里", "悪魔偽王国軍（ディアボロス）", "ゲーム全般", 22, "人見知りであまのじゃくな女の子", 40, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アヤネ", 148, "B", 14, 102301, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 5, 0, "ヒューマン", "芹澤優", "サレンディア救護院", "屋内でできる遊び", 10, "ぷうきちといつも一緒！", 38, 9);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("スズメ", 154, "O", 15, 102501, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 12, 0, "ヒューマン", "悠木碧", "サレンディア救護院", "ご奉仕", 12, "お嬢さまのためにがんばるドジっ娘メイド", 43, 9);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("リン", 144, "B", 17, 102601, "test", 1, 0, "獣人族", "小岩井ことり", "牧場（エリザベスパーク）", "あんパン", 1, "遊びと睡眠が何より大事なぐうたら娘", 42, 11);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("エリコ", 154, "B", 16, 102701, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 0, "魔族", "橋本ちなみ", "トワイライトキャラバン", "実験、裁縫、料理", 30, "運命の相手に一途すぎる乙女", 43, 13);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("サレン", 156, "A", 17, 102801, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 0, "エルフ", "堀江由衣", "サレンディア救護院", "経営、お茶会", 4, "救護院を経営する優しい庶民派お嬢様", 43, 9);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ノゾミ", 157, "B", 17, 102901, "いつか世界中の人達をファンにしてみせる！\nトップアイドルになるその日まで、\n応援よろしくね♪", 1, 0, "ヒューマン", "日笠陽子", "カルミナ", "舞台鑑賞、ダンス", 24, "歌って踊れる大人気アイドル", 40, 4);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ニノン", 163, "O", 16, 103001, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 0, "ヒューマン", "佐藤聡美", "ヴァイスフリューゲル　ランドソル支部", "忍法開発", 31, "トーゴクの神秘、オシエテクダサイ！", 51, 15);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("シノブ", 157, "AB", 18, 103101, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 0, "魔族", "大坪由佳", "悪魔偽王国軍（ディアボロス）", "占い", 22, "占いが得意な霊能少女", 42, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アキノ", 157, "AB", 18, 103201, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 3, 0, "ヒューマン", "松嵜麗", "メルクリウス財団", "慈善事業", 12, "一人前の商人を目指すパワフルお嬢様", 45, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("マヒル", 142, "B", 20, 103301, "オラはどんな時でもみんなに笑顔を届ける\n最高の芸人目指してる！\n一緒に頑張るべ！", 3, 0, "ヒューマン", "新田恵海", "牧場（エリザベスパーク）", "漫才", 3, "みんなを笑顔にするお笑い牧場主", 35, 11);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ユカリ", 164, "A", 22, 103401, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 0, "エルフ", "今井麻美", "メルクリウス財団", "ウインドーショッピング", 16, "純情でほっとけない大人の女性", 55, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("キョウカ", 118, "A", 8, 103601, "test", 2, 0, "エルフ", "小倉唯", "リトルリリカル", "お勉強", 2, "礼儀正しくしっかり者のちびっ子優等生", 21, 5);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("トモ", 149, "A", 13, 103701, "test", 8, 0, "ヒューマン", "茅原実里", "王宮騎士団（NIGHTMARE）", "剣術、年長者をからかう", 11, "義理堅くてからかい好きな剣術少女", 43, 8);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("シオリ", 153, "A", 14, 103801, "ゴホッ、ゴホッ…か、身体は弱いけど、\nせめて気持ちだけでも前向きに…！\nあっ、でもダメ…立ちくらみが…", 11, 0, "獣人族", "小清水亜美", "牧場（エリザベスパーク）", "読書、お散歩", 3, "読書が趣味の病弱少女", 40, 11);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アオイ", 158, "AB", 13, 104001, "友達ができるその日まで…\nBB団で\nトレーニングですっ！", 6, 0, "エルフ", "花澤香菜", "フォレスティエ", "友達作りのイメトレ", 6, "「友達」に憧れる、エルフの森の女の子", 44, 6);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("チカ", 163, "O", 17, 104201, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 0, "ヒューマン", "福原綾香", "カルミナ", "各種楽器", 3, "人々を守るために歌う、唱喚士の少女", 46, 4);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("マコト", 168, "O", 17, 104301, "腹へってたら言えよな\n簡単でよければ\nすっげー旨いもん食わせてやるよ！", 8, 0, "獣人族", "小松未可子", "自警団（カォン）", "お菓子作り", 9, "男勝りで情に厚いワイルド娘", 54, 10);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("イリヤ", 172, "A", "??", 104401, "test", 5, 0, "魔族", "丹下桜", "悪魔偽王国軍（ディアボロス）", "世界征服", 5, "かつては夜を支配した最強の吸血鬼", 50, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("クウカ", 157, "AB", 18, 104501, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 0, "ヒューマン", "長妻樹里", "ヴァイスフリューゲル　ランドソル支部", "小説を読むこと", 19, "妄想大好き！　ほんとは照れ屋な女の子", 49, 15);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("タマキ", 158, "AB", 19, 104601, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 0, "獣人族", "沼倉愛美", "メルクリウス財団", "猫とたわむれること", 1, "弱きを助け強きをくじく猫娘", 48, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ジュン", 171, "A", 25, 104701, "？？？", 10, 0, "ヒューマン", "川澄綾子", "王宮騎士団（NIGHTMARE）", "格闘技、湯浴み", 25, "素顔を見せない冷静沈着な女性騎士", 50, 8);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミフユ", 163, "O", 20, 104801, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 0, "ヒューマン", "田所あずさ", "メルクリウス財団", "傭兵などのアルバイト", 11, "仕事も私事も効率優先な傭兵少女", 49, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("シズル", 168, "O", 18, 104901, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 0, "ヒューマン", "生天目仁美", "ラビリンス", "家事全般", 24, "お姉ちゃんがお世話してあげるからねっ！", 54, 3);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミサキ", 120, "A", 11, 105001, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 1, 0, "魔族", "久野美咲", "ルーセント学院", "ファッション誌鑑賞、コスメ集め", 3, "ちょっとおませな恋に恋する女の子", 22, 14);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミツキ", 166, "A", 27, 105101, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 3, 0, "ヒューマン", "三石琴乃", "トワイライトキャラバン", "研究、実験", 7, "実験が趣味の危険な科学者", 53, 13);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("リマ", 150, "A", 17, 105201, "私、ごく普通の、どこにでもいる女の子よ！\nみ、見た目以外はね…", 3, 0, "獣人族", "徳井青空", "牧場（エリザベスパーク）", "毛繕い、お喋り", 14, "乙女チックなもふもふアニマル", 100, 11);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("モニカ", 140, "A", 17, 105301, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 7, 0, "ヒューマン", "辻あゆみ", "ヴァイスフリューゲル　ランドソル支部", "お菓子屋通い", 28, "見た目も中身もお子ちゃまな異国の軍人", 33, 15);
