INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ジータ", 156, "O", 17, 105701, "私ね、一人前の騎空士になりたいんだ\nいつか父さんみたいな騎空士になって、\n空の果てまで旅する。それが私の夢だよ！", 3, 0, "ヒューマン", "金元寿子", "？？？", "冒険、おしゃべり", 10, "空への冒険を夢見る騎空士の少女", 45, "");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ペコリーヌ", 156, "O", 17, 105801, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 0, "ヒューマン", "M・A・O", "美食殿", "食べ歩き、料理", 31, "いつも元気な腹ペコ少女", 46, 1);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("コッコロ", 140, "B", 11, 105901, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 0, "エルフ", "伊藤美来", "美食殿", "瞑想、動植物の飼育", 11, "主を慕う、小さなガイド役", 35, 1);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("キャル", 152, "A", 14, 106001, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 0, "獣人族", "立花理香", "美食殿", "猫と遊ぶ", 2, "行き倒れの謎のネコミミ魔法使い", 39, 1);
