INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ペコリーヌ（サマー）", 156, "O", 17, 107501, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 0, "ヒューマン", "M・A・O", "美食殿", "食べ歩き、料理", 31, "いつも元気な腹ペコ少女", 46, 1);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("コッコロ（サマー）", 140, "B", 11, 107601, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 0, "エルフ", "伊藤美来", "美食殿", "瞑想、動植物の飼育", 11, "主を慕う、小さなガイド役", 35, 1);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("スズメ（サマー）", 154, "O", 15, 107701, "うぅ…ごめんなさい～…\nまたキッチンを爆発させてしまいました～\nこれじゃあメイド失格です…", 12, 0, "ヒューマン", "悠木碧", "サレンディア救護院", "ご奉仕", 12, "お嬢さまのためにがんばるドジっ娘メイド", 43, 9);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("キャル（サマー）", 152, "A", 14, 107801, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 0, "獣人族", "立花理香", "美食殿", "猫と遊ぶ", 2, "行き倒れの謎のネコミミ魔法使い", 39, 1);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("タマキ（サマー）", 158, "AB", 19, 107901, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 0, "獣人族", "沼倉愛美", "メルクリウス財団", "猫とたわむれること", 1, "弱きを助け強きをくじく猫娘", 48, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミフユ（サマー）", 163, "O", 20, 108001, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 0, "ヒューマン", "田所あずさ", "メルクリウス財団", "傭兵などのアルバイト", 11, "仕事も私事も効率優先な傭兵少女", 49, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("シノブ（ハロウィン）", 157, "AB", 18, 108101, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 0, "魔族", "大坪由佳", "悪魔偽王国軍（ディアボロス）", "占い", 22, "占いが得意な霊能少女", 42, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミヤコ（ハロウィン）", 130, "B", 14, 108201, "難しいことはわからないの～\nただ毎日プリンを食べられるなら、\n幽霊のままでいいの～", 1, 0, "魔族", "雨宮天", "悪魔偽王国軍（ディアボロス）", "プリンを食べること", 23, "プリン大好きゴースト娘", 32, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミサキ（ハロウィン）", 120, "A", 11, 108301, "アタシのこと呼んだ？\nレディの魅力で夢中にさせてあげるわね！", 1, 0, "魔族", "久野美咲", "ルーセント学院", "ファッション誌鑑賞、コスメ集め", 3, "ちょっとおませな恋に恋する女の子", 22, 14);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("チカ（クリスマス）", 163, "O", 17, 108401, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 0, "ヒューマン", "福原綾香", "カルミナ", "各種楽器", 3, "人々を守るために歌う、唱喚士の少女", 46, 4);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("クルミ（クリスマス）", 150, "B", 12, 108501, "あの、えっと…私、く、クルミですぅ…\nふ、ふぇぇぇ…ど、どうしようぅ…\nは、恥かしくて…ご、ごめんなさいぃぃ！", 6, 0, "ヒューマン", "植田佳奈", "サレンディア救護院", "観劇、おままごと", 9, "泣き虫で臆病な守ってあげたい女の子", 40, 9);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アヤネ（クリスマス）", 148, "B", 14, 108601, "この子はね、ぷうきちって言うんだ\n武器なんだけど、しゃべるんだよ♪\n大事な大事な、私の友達なんだぁ～！", 5, 0, "ヒューマン", "芹澤優", "サレンディア救護院", "屋内でできる遊び", 10, "ぷうきちといつも一緒！", 38, 9);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ヒヨリ（ニューイヤー）", 155, "A", 16, 108701, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 0, "獣人族", "東山奈央", "トゥインクルウィッシュ", "人助け、応援", 27, "人助けが大好き！　前向き格闘娘", 44, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ユイ（ニューイヤー）", 158, "O", 17, 108801, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 0, "ヒューマン", "種田梨沙", "トゥインクルウィッシュ", "料理、人間観察", 5, "戦闘のサポートが得意な、心優しい少女", 47, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("レイ（ニューイヤー）", 163, "B", 18, 108901, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 0, "魔族", "早見沙織", "トゥインクルウィッシュ", "読書、乗馬、お茶", 12, "クールで何事にも真っ直ぐな剣士", 46, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("エリコ（バレンタイン）", 154, "B", 16, 109001, "『壊し屋』の二つ名を持つ私…\nですが、怖がる必要はありませんわ\nあなた様は大切な運命の人ですから…", 7, 0, "魔族", "橋本ちなみ", "トワイライトキャラバン", "実験、裁縫、料理", 30, "運命の相手に一途すぎる乙女", 43, 13);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("シズル（バレンタイン）", 168, "O", 18, 109101, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 0, "ヒューマン", "生天目仁美", "ラビリンス", "家事全般", 24, "お姉ちゃんがお世話してあげるからねっ！", 54, 3);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アン", 156, "AB", 17, 109201, "私はアン！一応、マナリア王国の\n第一王女だけど…あまりかしこまらないで、\n気軽に仲良くしてくれたら嬉しいな！", 12, 0, "ヒューマン", "日笠陽子", "？？？", "読書", 1, "英霊と契約を結んだマナリアの天才王女", 55, "");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ルゥ", 144, "O", 16, 109301, "ルゥはルゥですぅ！マナリア魔法学院に\n通ってるですぅ。あなたもルゥの\nお友だちになってくれるですか？", 2, 0, "ヒューマン", "こやまきみこ", "？？？", "食べること、眠ること", 4, "マナリア魔法学院の新入生", 45, "");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("グレア", 167, "B", 17, 109401, "私はグレア。竜と人、両方の血を\n受け継いでいるの…\nえっと…よ、よろしくね", 11, 0, "半人半竜", "福原綾香", "？？？", "ピアノ", 3, "人を超越した力を有す心優しい竜姫", 67, "");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("クウカ（オーエド）", 157, "AB", 18, 109501, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 0, "ヒューマン", "長妻樹里", "ヴァイスフリューゲル　ランドソル支部", "小説を読むこと", 19, "妄想大好き！　ほんとは照れ屋な女の子", 49, 15);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ニノン（オーエド）", 163, "O", 16, 109601, "スシ、ゲイシャ、テンプラ…\nはふぅ～！\nトーゴクの文化はステキデスね～！", 8, 0, "ヒューマン", "佐藤聡美", "ヴァイスフリューゲル　ランドソル支部", "忍法開発", 31, "トーゴクの神秘、オシエテクダサイ！", 51, 15);
