INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ぺコリーヌ（ニューイヤー）", 156, "O", 17, 111801, "あ、あの…何か食べ物持っていませんか？\nもう、お腹ペコペコで…", 3, 0, "ヒューマン", "M・A・O", "美食殿", "食べ歩き、料理", 31, "いつも元気な腹ペコ少女", 46, 1);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("コッコロ（ニューイヤー）", 140, "B", 11, 111901, "主さまのガイド役を仰せつかりました\nわたくし、主さまに満足していただけるよう\n誠心誠意尽くさせていただきます", 5, 0, "エルフ", "伊藤美来", "美食殿", "瞑想、動植物の飼育", 11, "主を慕う、小さなガイド役", 35, 1);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("キャル（ニューイヤー）", 152, "A", 14, 112001, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 0, "獣人族", "立花理香", "美食殿", "猫と遊ぶ", 2, "行き倒れの謎のネコミミ魔法使い", 39, 1);
