INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("リン（レンジャー）", 144, "B", 17, 112701, "", 1, 0, "獣人族", "小岩井ことり", "牧場（エリザベスパーク）", "あんパン", 1, "遊びと睡眠が何より大事なぐうたら娘", 42, 11);
