INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("リノ（ワンダー）", 156, "A", 15, 112901, "覚えていないと思うんですけど…\n私は妹なんですよ！\nだからお兄ちゃんって呼んでいいですか？", 8, 0, "ヒューマン", "阿澄佳奈", "ラビリンス", "お裁縫", 25, "人懐っこくてマシンガントークな妹系少女", 44, 3);
