INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アンナ（サマー）", 159, "A", 17, 113201, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 0, "魔族", "髙野麻美", "トワイライトキャラバン", "小説執筆", 5, "前世を信じる中二病患者、「疾風の冥姫」", 45, 13);
