INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ジュン（サマー）", 171, "A", 25, 113601, "", 10, 0, "ヒューマン", "川澄綾子", "王宮騎士団（NIGHTMARE）", "格闘技、湯浴み", 25, "素顔を見せない冷静沈着な女性騎士", 50, 8);
