INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ヨリ（エンジェル）", 150, "O", 13, 113801, "え、えっと…こ、こういうときって、\nどういうことを言えばいいんだっけ…\nうう、どうしてちゃんと喋れないの…", 11, 0, "魔族", "原紗友里", "悪魔偽王国軍（ディアボロス）", "ゲーム全般", 22, "人見知りであまのじゃくな女の子", 40, 7);
