INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("レイ（ハロウィン）", 163, "B", 18, 114001, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 0, "魔族", "早見沙織", "トゥインクルウィッシュ", "読書、乗馬、お茶", 12, "クールで何事にも真っ直ぐな剣士", 46, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("マツリ（ハロウィン）", 146, "O", 12, 114101, "", 11, 0, "獣人族", "下田麻美", "王宮騎士団（NIGHTMARE）", "ヒーローごっこ", 25, "ヒーローに憧れる騎士見習いの少女", 40, 8);
