INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アキノ（クリスマス）", 157, "AB", 18, 114401, "この私とともにいる限り、\nお金に不自由はさせませんわ！", 3, 0, "ヒューマン", "松嵜麗", "メルクリウス財団", "慈善事業", 12, "一人前の商人を目指すパワフルお嬢様", 45, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("サレン（クリスマス）", 156, "A", 17, 114501, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 0, "エルフ", "堀江由衣", "サレンディア救護院", "経営、お茶会", 4, "救護院を経営する優しい庶民派お嬢様", 43, 9);
