INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("マホ（シンデレラ）", 155, "O", 16, 116001, "マホマホ王国のお姫はんの、マホ姫どす！\nけったいな顔してどないしはったん？\nマホマホ王国はずーっと遠くの国なんどす？", 9, 0, "獣人族", "内田真礼", "自警団（カォン）", "空想、ぬいぐるみ集め", 22, "マホマホ王国のプリンセス", 42, 10);
