INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("タマキ（作業服）", 158, "AB", 19, 116801, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 0, "獣人族", "沼倉愛美", "メルクリウス財団", "猫とたわむれること", 1, "弱きを助け強きをくじく猫娘", 48, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミフユ（作業服）", 163, "O", 20, 116901, "私がキミの師匠になってあげる！\nもちろんタダとはいかないわ\n時給はしっかりもらうから", 11, 0, "ヒューマン", "田所あずさ", "メルクリウス財団", "傭兵などのアルバイト", 11, "仕事も私事も効率優先な傭兵少女", 49, 12);
