INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("シズル（サマー）", 168, "O", 18, 117101, "身の回りのお世話はお姉ちゃんがやってあげるね！\nお料理も、お洗濯も、お掃除も\nお風呂で背中も流してあげちゃうぞっ！", 10, 0, "ヒューマン", "生天目仁美", "ラビリンス", "家事全般", 24, "お姉ちゃんがお世話してあげるからねっ！", 54, 3);
