INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("チカ（サマー）", 163, "O", 17, 117301, "私は人々の平和を守るため、唱喚術を使って\n戦います。…最近は、ア、アイドルとしても\n活動してますが、そちらはまだ不慣れで…", 6, 0, "ヒューマン", "福原綾香", "カルミナ", "各種楽器", 3, "人々を守るために歌う、唱喚士の少女", 46, 4);
