INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミツキ（オーエド）", 166, "A", 27, 117501, "私は科学者だけど、\n医者の真似事もしてるの\n病気になったら診てあげるわ", 3, 0, "ヒューマン", "三石琴乃", "トワイライトキャラバン", "研究、実験", 7, "実験が趣味の危険な科学者", 53, 13);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ユキ（オーエド）", 150, "AB", 14, 117601, "ボクって本当に美しいなあ…\n可愛くて美しいなんて本当に罪だと思うけど\n生まれもったものだから仕方ないんだ♪", 10, 0, "エルフ", "大空直美", "ヴァイスフリューゲル　ランドソル支部", "鏡で自分を見ること", 10, "ボクは誰よりも美しい", 40, 15);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("カオリ（ハロウィン）", 158, "A", 17, 117701, "ハイターイ！　歌って踊って、\n最高に盛り上がるさ～！\nやさやさ、キミも一緒に踊るさ～！", 7, 0, "獣人族", "高森奈津美", "自警団（カォン）", "踊り、空手", 7, "いつでも「なんくるないさ～」な天然娘", 53, 10);
