INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("イノリ（怪盗）", 145, "AB", 13, 121601, "", 9, 0, "ドラゴン族", "藤田茜", "ドラゴンズネスト", "ゲーム", 29, "口が達者なヘタレドラゴン", "???", 17);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アンナ（パイレーツ）", 159, "A", 17, 121901, "いいか、絶対に私を真名で呼ぶなよ？\n常に「機関」の眼や耳の存在を疑え\nそれが、生きのびるための術だ…！", 7, 0, "魔族", "髙野麻美", "トワイライトキャラバン", "小説執筆", 5, "前世を信じる中二病患者、「疾風の冥姫」", 45, 13);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("シノブ（パイレーツ）", 157, "AB", 18, 122001, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 0, "魔族", "大坪由佳", "悪魔偽王国軍（ディアボロス）", "占い", 22, "占いが得意な霊能少女", 42, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("アオイ（キャンプ）", 158, "AB", 13, 122101, "", 6, 0, "エルフ", "花澤香菜", "フォレスティエ", "友達作りのイメトレ", 6, "「友達」に憧れる、エルフの森の女の子", 44, 6);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ユカリ（キャンプ）", 164, "A", 22, 122201, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 0, "エルフ", "今井麻美", "メルクリウス財団", "ウインドーショッピング", 16, "純情でほっとけない大人の女性", 55, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ヴァンピィ", 149, "AB", "??", 122301, "", 12, 0, "魔族", "釘宮理恵", "？？？", "お散歩、お料理", 6, "けんぞくのご主人様", 41, "");
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ヒヨリ（サマー）", 155, "A", 16, 122401, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 0, "獣人族", "東山奈央", "トゥインクルウィッシュ", "人助け、応援", 27, "人助けが大好き！　前向き格闘娘", 44, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("レイ（サマー）", 163, "B", 18, 122501, "キミと会ったのもきっと何かの縁だ\n一緒に塔の頂上を目指す仲間として\n頑張っていこう。よろしく頼む", 1, 0, "魔族", "早見沙織", "トゥインクルウィッシュ", "読書、乗馬、お茶", 12, "クールで何事にも真っ直ぐな剣士", 46, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ユイ（サマー）", 158, "O", 17, 122601, "あんまり役に立てるかはわからないけど…\nわたしも頑張って、\nみんなをサポートするね！", 4, 0, "ヒューマン", "種田梨沙", "トゥインクルウィッシュ", "料理、人間観察", 5, "戦闘のサポートが得意な、心優しい少女", 47, 2);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("キョウカ（サマー）", 118, "A", 8, 122701, "", 2, 0, "エルフ", "小倉唯", "リトルリリカル", "お勉強", 2, "礼儀正しくしっかり者のちびっ子優等生", 21, 5);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミソギ（サマー）", 128, "O", 9, 122801, "イタズラなら任せて！\nにいちゃん、引っかからないように気を付けなよー♪", 8, 0, "ヒューマン", "諸星すみれ", "リトルリリカル", "いたずら、探検", 10, "探検好きのイタズラっ子", 27, 5);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ミミ（サマー）", 117, "O", 10, 122901, "ぴょんぴょん、うさぎさんになりたいな～♪　\nミミ、うさぎさんになれたら、\n最初におにいちゃんに見せてあげるね！", 4, 0, "獣人族", "日高里菜", "リトルリリカル", "かわいいもの集め", 3, "お歌もにんじんも、ウサギさんも大好き♪", 21, 5);
