INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("タマキ（カフェ）", 158, "AB", 19, 125101, "お金もうけの話なら、ぜひともあたしに\n持ってくるにゃ！　稼げるなら１ルピだって\n見逃さないのが、あたしの信条にゃ～♪", 3, 0, "獣人族", "沼倉愛美", "メルクリウス財団", "猫とたわむれること", 1, "弱きを助け強きをくじく猫娘", 48, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("モニカ（カフェ）", 140, "A", 17, 125201, "「白き翼」こと、ヴァイスフリューゲル…\nその名に恥じぬよう、天高く舞い、\n華麗に敵を倒してみせる！", 7, 0, "ヒューマン", "辻あゆみ", "ヴァイスフリューゲル　ランドソル支部", "お菓子屋通い", 28, "見た目も中身もお子ちゃまな異国の軍人", 33, 15);
