INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ユカリ（サマー）", 164, "A", 22, 126801, "キミには情けないところばかり\n見られているけど、こんなところ、\nキミ以外には見せないんだからね？", 3, 0, "エルフ", "今井麻美", "メルクリウス財団", "ウインドーショッピング", 16, "純情でほっとけない大人の女性", 55, 12);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ランファ（サマー）", 165, "O", 20, 126901, "", 12, 0, "魔族", "原田彩楓", "レイジ・レギオン", "歌、読書、詩を書くこと", 28, "静寂を求め歌う陰気少女", 53, 19);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("クウカ（サマー）", 157, "AB", 18, 127001, "あなたのことを考えていました\n…逆らえないクウカをああして、こうして\nぐふ、ぐふふふ…", 11, 0, "ヒューマン", "長妻樹里", "ヴァイスフリューゲル　ランドソル支部", "小説を読むこと", 19, "妄想大好き！　ほんとは照れ屋な女の子", 49, 15);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("シノブ（サマー）", 157, "AB", 18, 127101, "私、小さい頃から人には見えないものが\n見えていたんです。今もあなたの後ろに\n一人、二人、三人…賑やかですね", 12, 0, "魔族", "大坪由佳", "悪魔偽王国軍（ディアボロス）", "占い", 22, "占いが得意な霊能少女", 42, 7);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("キャル（編入生）", 152, "A", 14, 127201, "なに、モタモタしてんのよ\n仕方ないから、あたしが手伝ってあげるわ\nいい？　感謝しなさいよね！", 9, 0, "獣人族", "立花理香", "美食殿", "猫と遊ぶ", 2, "行き倒れの謎のネコミミ魔法使い", 39, 1);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("スズナ（編入生）", 167, "O", 17, 127301, "ヒデサイ、ちょっす～！　うち、漢字と計算は\nちょっち…てか、おに苦手なんだ～\nでもでも、ファッションだったら任せて～！", 4, 0, "魔族", "上坂すみれ", "ルーセント学院", "ファッション", 10, "天真爛漫で人気者のカリスマモデル", 48, 14);
INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("サレン（サラサリア）", 156, "A", 17, 127501, "貧乏性？　いいえ、\n「もったいない」の精神で\n日々を過ごしてるだけよ！", 10, 0, "エルフ", "堀江由衣", "サレンディア救護院", "経営、お茶会", 4, "救護院を経営する優しい庶民派お嬢様", 43, 9);
