INSERT INTO `v1_bdb790958cf34a91fb2fcbd6ba56479fc7b23a45d7babffba6c8ab4e58f75875` VALUES ("ヒヨリ（プリンセス）", 155, "A", 16, 180101, "こんにちは！　ヒヨリでっす！\n困っている人がいたら助けにいくよ！\nよかったら一緒に来ない？", 8, 0, "獣人族", "東山奈央", "トゥインクルウィッシュ", "人助け、応援", 27, "人助けが大好き！　前向き格闘娘", 44, 2);
